import React from 'react';

function Achievements({ data }) {
  if (!data) return null;

  return (
    <section id="achievements" className="py-12 md:py-16 bg-white">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Achievements</h2>
          <div className="space-y-4">
            {data.map((achievement) => (
              <div key={achievement.id} className="flex items-center gap-4 p-4 rounded-lg border border-gray-200 hover:bg-gray-50 transition">
                <div className="text-2xl">🏆</div>
                <div className="flex-1">
                  <h3 className="font-semibold text-gray-900">{achievement.title}</h3>
                  <p className="text-sm text-gray-500">{achievement.year}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Achievements;
